evals.cmd:
set -e; d=$(mktemp -d); git clone -q --depth 1 -b fix/telegram-emit-channel https://github.com/blueman82/assistant-agent.git "$d"; cd "$d"; npm install --silent >/dev/null 2>&1; cat > bridge/__eval_n1.ts <<'PROBE'
import assert from "node:assert/strict";
process.env["RACHEL_TELEGRAM_TOKEN"] = "eval-fake-token";
process.env["RACHEL_TELEGRAM_CHAT_ID"] = "424242";
const { runTurn } = await import("../rachel.ts");
const fakeQuery = ((_args: unknown) => (async function* () {
  yield { type: "system", subtype: "init", session_id: "eval-session" };
  yield { type: "assistant", message: { content: [
    { type: "tool_use", name: "mcp__probe__calendar_lookup", input: { day: "today" }, id: "tu1" },
    { type: "text", text: "Nothing on this afternoon. Evening free too." },
  ] } };
  yield { type: "result", num_turns: 2, total_cost_usd: 0.0123 };
})()) as never;
const lines: string[] = [];
await runTurn("whats on", ((line: string, ...rest: unknown[]) => { void rest; lines.push(line); }) as never, new AbortController().signal, fakeQuery);
const { createBridge } = await import("./telegram-bridge.ts");
void createBridge;
const sent: string[] = [];
const transport = (async (_url: unknown, init: { body?: unknown }) => {
  const body = JSON.parse(String(init?.body ?? "{}"));
  if (typeof body.text === "string") sent.push(body.text);
  return { ok: true, json: async () => ({ ok: true, result: {} }) } as Response;
}) as unknown as typeof fetch;
const { sendChunked } = await import("./api.ts");
const bridgeEmit: string[] = [];
await runTurn("whats on", ((line: string, kind?: string) => { if (kind === undefined || kind === "text") bridgeEmit.push(line); }) as never, new AbortController().signal, fakeQuery);
await sendChunked({ token: "eval-fake-token", chatId: "424242", transport }, bridgeEmit.join("\n").trim());
const out = sent.join("");
assert.ok(out.includes("Nothing on this afternoon"), "model text lost: " + JSON.stringify(out));
assert.ok(!out.includes("mcp__probe__calendar_lookup"), "tool echo leaked: " + JSON.stringify(out));
assert.ok(!out.includes("done turns="), "done footer leaked: " + JSON.stringify(out));
console.log("N1 PASS");
PROBE
node --experimental-strip-types bridge/__eval_n1.ts

