if node --experimental-strip-types bridge/__eval_n1.ts; then echo 'NEG CONTROL FAILED: probe passed on base SHA (flat emit should leak tool echo and footer)'; exit 1; else echo 'negative control ok: probe fails on base SHA'; fi
